/**
 * @summary Search pharmacies and medicines
 */
export const getListPharmaciesUrl = (params?: ListPharmaciesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/pharmacies?${stringifiedParams}`
    : `/api/pharmacies`;
};

export const listPharmacies = async (
  params?: ListPharmaciesParams,
  options?: RequestInit,
): Promise<Pharmacy[]> => {
  return customFetch<Pharmacy[]>(getListPharmaciesUrl(params), {
    ...options,
    method: "GET",
  });
};

